// n8n: CODE - Build Live Speech Relay Context
// After: HTTP - Fetch Session (start branch)
// Returns system instructions + session context for Gemini Live relay server.

function parseJson(raw, fallback) {
  if (raw == null) return fallback;
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (_) {
    return fallback;
  }
}

function safeEnv(name) {
  try {
    return String($env[name] || '').trim();
  } catch (_) {
    return '';
  }
}

const norm = $('CODE - Normalize Live Speech Start').first().json;
const cfg = norm.config || {};
const fetchRaw = $input.first().json;
const session = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;
if (!session?.id) throw new Error('Session not found for live speech start');

const sessCfg = { ...parseJson(session.config, {}), ...cfg };
const screening = parseJson(session.screening, {});
const jdTitle = String(
  sessCfg.requisition_title || screening.requisition_title || 'Open role'
).trim();
const jdReq = String(
  sessCfg.requisition_requirements || screening.requisition_requirements || ''
).trim();
const cvText = String(session.cv_plaintext || screening.cv_plaintext || '').slice(0, 12000);
const maxQ = Number(sessCfg.max_questions || cfg.max_questions || 5);
const speechTurns = Number(cfg.speech_phases || sessCfg.speech_phases || 5);

const systemInstruction = `You are a professional English voice interviewer for ${jdTitle} at ${cfg.organization_name || 'CONVO'}.

LANGUAGE (critical — ONLY for genuinely non-English speech):
- Speak ONLY in clear professional English.
- The candidate MUST answer in English. Transcription is configured for English (en-US) only.
- ONLY when the candidate actually speaks in Urdu, Hindi, Arabic, or another non-English language: warmly and briefly say something like "I'm sorry, this interview is in English — could you please answer in English?" and then RE-ASK THE SAME current question. Do NOT move on.
- NEVER tell a candidate to "speak in English" when they are already speaking English. An answer that is in English but weak, unclear, or off-topic is NOT a language problem — never respond to it with an English-language request.
- A non-English answer is scored ZERO for that response.
- Never output internal notes, markdown, headings, bullet reasoning, partial words, or meta commentary. Speak only complete, polished interview sentences.

OFF-TOPIC / IRRELEVANT ANSWERS (critical — stay on the SAME question, in English):
- If the candidate's answer is in English but clearly off-topic, unrelated, or a random counter-question (e.g. "who is the prime minister of Pakistan"), do NOT ask them to speak in English and do NOT advance.
- Instead, in ONE short, warm, encouraging sentence, gently let them know that response seems off-topic and guide them back to the question, then re-ask the SAME question. Be kind and professional — never say things like "this is an irrelevant question".
- A genuine but weak, short, or "I don't know" answer is acceptable — accept it and move on; do NOT treat it as off-topic.

REPEAT & CLARIFICATION (critical — stay on the SAME question):
- If the candidate asks you to repeat, rephrase, or says they did not understand/hear the question, first warmly reassure them in ONE short sentence (e.g. "No problem — let me repeat the question.") and then calmly repeat the SAME current question. Do NOT advance to the next question, and do NOT say "let's move on" or "continue".
- If the candidate is hesitant or asks for a moment, reassure them ("Take your time") and keep waiting on the SAME question.
- Only advance to the next numbered question after the candidate has actually attempted an answer to the current one in English.

TURN-TAKING (critical — this is a strict push-to-talk interview):
- This is NOT a free-flowing chat. The candidate uses a button to speak; you only hear them during their turn.
- YOU speak first, and you always wait for the system to prompt you for each new step.
- Ask exactly ONE thing per turn, then STOP talking completely and wait. Do not add filler, do not keep talking, do not repeat yourself.
- Each turn must contain at most ONE question mark. Never ask two questions in the same turn.
- After the candidate's turn ends, you MAY open with ONE short, warm acknowledgement of their previous answer (e.g. "Thank you for sharing that.", "Great, I appreciate the detail.") and then ask the next single question. Keep the acknowledgement to one brief sentence — do NOT rate, score, critique, or give detailed feedback, and do NOT turn it into a second question.
- Keep every question to 1-2 sentences. Be concise and clear.

WARM-UP PHASE (happens FIRST — two separate steps before the numbered questions):

Step A — Microphone check (your VERY FIRST response):
- Greet the candidate warmly in one short sentence, welcome them to the interview.
- Tell them you want to do a quick microphone check and ask them to say just a few words — anything at all.
- STOP after the mic-check request. Do NOT ask for an introduction yet. Wait.

Step B — Introduction (only after the mic check response):
- The system will prompt you to ask for an introduction.
- Ask the candidate to briefly introduce themselves (name, background, interest in the role). 1-2 warm sentences only.
- STOP after asking for the intro. Wait for their answer. Do NOT start question 1 yet.

SESSION FLOW (critical):
- After the warm-up, the system prompts you to ask numbered questions. Ask exactly ${speechTurns} questions total, one at a time, in order.
- Do NOT say "Question 1", "Question 2", etc. aloud — NEVER number questions in your speech.
- Questions 1 through ${speechTurns - 1}: after each answer, ask the NEXT question only. Never thank or close early.
- ONLY after the candidate finishes answering question ${speechTurns} (the last question) may you thank them in one sentence and say the voice interview is complete. Then stop speaking.
- Until question ${speechTurns} is asked AND answered, never say the interview is complete, never say goodbye, and never say "we will be in touch".
- Do NOT ask a question beyond number ${speechTurns}. Do NOT continue chatting after the closing thank-you.

SCORING (internal only — never say scores aloud):
- After each answer, mentally score 0-100 on relevance, clarity, confidence, professionalism.
- A response given in a non-English language is scored ZERO.
- An off-topic or irrelevant response scores very low on relevance.

SILENCE & ENGAGEMENT:
- If the candidate goes quiet, the system will instruct you to nudge them. When that happens, SPEAK ONE short, warm encouraging sentence (e.g. "Take your time — whenever you're ready, please go ahead and share your answer.").
- Do NOT repeat the full question during a silence nudge. Say only the single encouraging sentence and stop.

CROSS-QUESTIONING (follow-up):
- When instructed to ask a follow-up, ask ONE short probe on the SAME topic so the candidate can clarify or give a concrete example.
- Follow-ups do NOT count as a new numbered question — stay on the same question number until the follow-up is answered.
- The follow-up must be a single question with one question mark only.

QUESTION STYLE:
- Conceptual, scenario, and behavioural questions relevant to the role. Avoid yes/no questions.
- Spread across these themes (one per question): communication under pressure, motivation for this role, collaboration and teamwork, handling setbacks or conflict, growth mindset and self-reflection.

JOB CONTEXT:
${jdReq.slice(0, 4000)}

CANDIDATE CV (reference silently — never say "on your CV"):
${cvText.slice(0, 6000) || '(limited CV context)'}`;

const kickoffPrompt = `Begin the interview now in English. In the SAME single response: greet the candidate in one short sentence, then immediately ask question 1 of ${speechTurns} for the ${jdTitle} role. Ask only that one question, then stop talking and wait for the candidate. Do not number the question aloud and do not say anything after it.`;

const completeWebhook = String(
  cfg.live_complete_webhook ||
    (cfg.n8n_public_url
      ? `${String(cfg.n8n_public_url).replace(/\/+$/, '')}/webhook/talent/live-speech-complete`
      : '')
).trim();
const relayUrl = String(cfg.live_relay_url || sessCfg.live_relay_url || '').trim();
const supabaseUrl = String(
  cfg.supabase_url ||
    sessCfg.supabase_url ||
    safeEnv('SUPABASE_URL') ||
    ''
).trim();
const supabaseKey = String(
  cfg.supabase_key ||
    sessCfg.supabase_key ||
    safeEnv('SUPABASE_SERVICE_ROLE_KEY') ||
    safeEnv('SUPABASE_KEY') ||
    ''
).trim();
const portalBase = String(
  cfg.portal_base_url || sessCfg.portal_base_url || 'https://talent-acquisition-six.vercel.app'
).replace(/\/+$/, '');

return [
  {
    json: {
      ok: true,
      flow: 'live_speech_start',
      session_id: session.id,
      candidate_email: norm.candidate_email || session.candidate_email,
      assessment_mode: 'live_speech',
      max_questions: maxQ,
            speech_phases: speechTurns,
      speech_answer_seconds: Number(cfg.speech_answer_seconds || sessCfg.speech_answer_seconds || 120),
      silence_handling_enabled: cfg.silence_handling_enabled !== false,
      silence_nudge_seconds: Number(cfg.silence_nudge_seconds || sessCfg.silence_nudge_seconds || 5),
      silence_auto_submit_seconds: Number(cfg.silence_auto_submit_seconds || sessCfg.silence_auto_submit_seconds || 6),
      silence_nudge_text: String(cfg.silence_nudge_text || sessCfg.silence_nudge_text || "Take your time — whenever you're ready, please go ahead and share your answer."),
      followup_min_words: Number(cfg.followup_min_words || sessCfg.followup_min_words || 30),
      // Default OFF so candidates always get Q2 after Q1. Enable per-job if needed.
      follow_up_enabled: Boolean(cfg.follow_up_enabled || sessCfg.follow_up_enabled),
      // Realistic repeat / language handling — both keep the candidate on the SAME question.
      max_question_repeats: Number(cfg.max_question_repeats || sessCfg.max_question_repeats || 3),
      max_non_english_nudges: Number(cfg.max_non_english_nudges || sessCfg.max_non_english_nudges || 2),
      // Off-topic guard: gently redirect a clearly irrelevant English answer and
      // stay on the SAME question (bounded so a false positive costs one re-ask).
      relevance_guard_enabled: cfg.relevance_guard_enabled !== false,
      max_irrelevant_redirects: Number(cfg.max_irrelevant_redirects ?? sessCfg.max_irrelevant_redirects ?? 1),
      // Brief, warm acknowledgement of the previous answer before the next question.
      appreciation_enabled: cfg.appreciation_enabled !== false,
      coaching_enabled: cfg.coaching_enabled !== false,
      voice_only: cfg.voice_only !== false,
      intro_enabled: cfg.intro_enabled !== false,
      intro_answer_seconds: Number(cfg.intro_answer_seconds || sessCfg.intro_answer_seconds || 90),
      current_phase: Number(session.current_phase || maxQ + 1),
      requisition_title: jdTitle,
      system_instruction: systemInstruction,
      kickoff_prompt: kickoffPrompt,
      gemini_live_model: String(
        cfg.gemini_live_model || 'gemini-2.5-flash-native-audio-preview-12-2025'
      ),
      gemini_text_model: String(cfg.gemini_text_model || 'gemini-2.5-flash'),
      live_relay_url: relayUrl,
      live_complete_webhook: completeWebhook,
      portal_base_url: portalBase,
      live_save_url: `${portalBase}/api/live-speech-save`,
      // Supabase creds at top-level so the relay can save directly without n8n.
      supabase_url: supabaseUrl,
      supabase_key: supabaseKey,
      config: {
        ...sessCfg,
        supabase_url: supabaseUrl,
        supabase_key: supabaseKey,
        portal_base_url: portalBase,
        n8n_public_url: String(cfg.n8n_public_url || sessCfg.n8n_public_url || '').replace(/\/+$/, ''),
        live_complete_webhook: completeWebhook,
      },
      n8n_public_url: String(cfg.n8n_public_url || '').replace(/\/+$/, ''),
      session,
    },
  },
];

// n8n: CODE - Parse Live Speech Result
// WORKFLOW: Talent Acquisition — Live Speech ONLY
// NODE: CODE - Parse Live Speech Result (after HTTP - Fetch Session Complete)
// DO NOT paste into Assessment workflow "CODE - Build LLM context" — use n8n_code_build_llm_context.js there.

function parseJson(raw, fallback) {
  if (raw == null) return fallback;
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (_) {
    return fallback;
  }
}

function pickNodeJson(name) {
  try {
    const raw = $(name).first().json;
    if (raw && typeof raw === 'object') return raw;
  } catch (_) {}
  return null;
}

function cleanEmail(raw) {
  const first = String(raw || '').trim().toLowerCase().split(/\n/)[0].trim();
  return first.split(/\s+regards/i)[0].trim();
}

// Optional session columns from supabase_live_speech_meta.sql — only PATCH keys that
// have values so missing columns (before migration) never break the save.
function buildLiveSpeechPatchMeta(norm) {
  const meta = {};
  const audioUrl = String(norm?.session_audio_url || '').trim();
  if (audioUrl) meta.live_speech_audio_url = audioUrl;
  const duration = Number(norm?.duration_seconds);
  if (Number.isFinite(duration) && duration > 0) {
    meta.live_speech_duration_seconds = Math.round(duration);
  }
  const tabSwitches = Number(norm?.tab_switches);
  if (Number.isFinite(tabSwitches) && tabSwitches >= 0) {
    meta.tab_switches = tabSwitches;
  }
  return meta;
}

function buildConfig(cfg) {
  const c = cfg || {};
  return {
    supabase_url: String(c.supabase_url || '').trim(),
    supabase_key: String(c.supabase_key || '').trim(),
    max_questions: Number(c.max_questions ?? 5),
    speech_phases: Number(c.live_speech_turns ?? c.speech_phases ?? 5),
    technical_weight: Number(c.technical_weight ?? 0.7),
    speech_weight: Number(c.speech_weight ?? 0.3),
    pass_score_threshold: Number(c.pass_score_threshold ?? 60),
    fail_score_threshold: Number(c.fail_score_threshold ?? 30),
    organization_name: String(c.organization_name || 'CONVO'),
    portal_base_url: String(c.portal_base_url || 'https://talent-acquisition-six.vercel.app'),
    interviewer_email: String(c.interviewer_email || ''),
    table_assessment_sessions: String(c.table_assessment_sessions || 'assessment_sessions'),
  };
}

function resolveLiveSpeechNorm() {
  const normalized = pickNodeJson('CODE - Normalize Live Speech Complete');
  if (normalized?.session_id && Array.isArray(normalized.turns) && normalized.turns.length) {
    return normalized;
  }

  const triggerRaw = pickNodeJson('TRG - Live Speech Complete');
  const cfgNode = pickNodeJson('CFG - Live Speech Config (complete)');
  const body = triggerRaw?.body || triggerRaw || {};
  const cfg = buildConfig(normalized?.config || cfgNode?.config || cfgNode);

  const session_id = String(
    body.session_id || body.sessionId || body.session_db_id || normalized?.session_id || ''
  ).trim();
  const candidate_email = cleanEmail(
    body.email || body.candidate_email || normalized?.candidate_email
  );
  const turns = Array.isArray(body.turns)
    ? body.turns
    : Array.isArray(normalized?.turns)
      ? normalized.turns
      : [];

  if (!session_id) {
    throw new Error(
      'live-speech-complete: session_id required — run from TRG - Live Speech Complete (not assessment-answer webhook).'
    );
  }
  if (!candidate_email) throw new Error('live-speech-complete: email required');
  if (!turns.length) {
    throw new Error(
      'live-speech-complete: turns[] required — relay must POST scored Q&A pairs to this webhook.'
    );
  }

  return {
    flow: normalized?.partial ? 'live_speech_turn' : 'live_speech_complete',
    partial: normalized?.partial === true || body.partial === true,
    session_id,
    candidate_email,
    assessment_mode: 'live_speech',
    turns,
    combined_speech_score:
      body.combined_speech_score != null
        ? Number(body.combined_speech_score)
        : normalized?.combined_speech_score ?? null,
    session_audio_url: String(
      body.session_audio_url || body.audio_url || normalized?.session_audio_url || ''
    ).trim(),
    duration_seconds: Number(body.duration_seconds || normalized?.duration_seconds || 0),
    final_feedback: String(
      body.final_feedback || body.feedback || normalized?.final_feedback || ''
    ).trim(),
    live_session_summary: String(
      body.live_session_summary || normalized?.live_session_summary || ''
    ).trim(),
    tab_switches: Number(body.tab_switches ?? body.tabSwitches ?? normalized?.tab_switches ?? 0),
    config: cfg,
  };
}

function computeTechnicalAverage(rows, maxQ) {
  const scores = rows
    .filter((row) => {
      const phase = Number(row.phase);
      return phase >= 1 && phase <= maxQ && row.score != null;
    })
    .map((row) => Number(row.score))
    .filter((n) => Number.isFinite(n));
  if (!scores.length) return null;
  return Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
}

function computeSpeechAverage(rows, maxQ, speechPhases) {
  const scores = rows
    .filter((row) => {
      const phase = Number(row.phase);
      return phase > maxQ && phase <= maxQ + speechPhases && row.score != null;
    })
    .map((row) => Number(row.score))
    .filter((n) => Number.isFinite(n));
  if (!scores.length) return null;
  return Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
}

async function lookupJobInterviewer(requisitionId, requisitionTitle, supabaseUrl, supabaseKey) {
  const sb = String(supabaseUrl || '').replace(/\/+$/, '');
  const key = String(supabaseKey || '').trim();
  if (!sb || !key) return '';
  const headers = { apikey: key, Authorization: `Bearer ${key}` };

  async function fetchFirst(url) {
    try {
      const res = await fetch(url, { headers });
      if (!res.ok) return '';
      const rows = await res.json();
      if (!Array.isArray(rows)) return '';
      for (const row of rows) {
        const email = String(row?.interviewer_email || '').trim().toLowerCase();
        if (email) return email;
      }
      return '';
    } catch (_) {
      return '';
    }
  }

  const reqId = String(requisitionId || '').trim();
  if (reqId) {
    const email = await fetchFirst(
      `${sb}/rest/v1/jobs?select=interviewer_email&job_id=eq.${encodeURIComponent(reqId)}&limit=1`
    );
    if (email) return email;
  }

  const title = String(requisitionTitle || '').trim();
  if (!title) return '';

  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 64);

  const urls = [
    `${sb}/rest/v1/jobs?select=interviewer_email&title=eq.${encodeURIComponent(title)}&limit=1`,
    `${sb}/rest/v1/jobs?select=interviewer_email&title=ilike.${encodeURIComponent(title)}&limit=3`,
    `${sb}/rest/v1/jobs?select=interviewer_email&title=ilike.${encodeURIComponent(`%${title.replace(/\s+/g, '%')}%`)}&limit=3`,
  ];
  if (slug && slug !== reqId) {
    urls.push(
      `${sb}/rest/v1/jobs?select=interviewer_email&job_id=eq.${encodeURIComponent(slug)}&limit=1`
    );
  }

  for (const url of urls) {
    const email = await fetchFirst(url);
    if (email) return email;
  }
  return '';
}

const norm = resolveLiveSpeechNorm();
const cfg = norm.config || {};
const fetchRaw = $input.first().json;
const session = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;
if (!session?.id) throw new Error('Session not found for live speech complete');

const sessionCfg = parseJson(session.config, {});
const sessCfg = { ...sessionCfg, ...cfg };
// JD intake stores interviewer on session.config — do not let blank n8n CFG wipe it.
const sessionInterviewer = String(sessionCfg.interviewer_email || '').trim();
if (sessionInterviewer) sessCfg.interviewer_email = sessionInterviewer;
const maxQ = Number(sessCfg.max_questions || cfg.max_questions || 5);
const speechPhases = Number(cfg.speech_phases || sessCfg.speech_phases || 5);
const passThreshold = Number(cfg.pass_score_threshold ?? 60);
const techWeight = Number(cfg.technical_weight ?? 0.7);
const speechWeight = Number(cfg.speech_weight ?? 0.3);
const iso = new Date().toISOString();

let history = session.interview_history;
history = parseJson(history, []);
if (!Array.isArray(history)) history = [];

const turns = Array.isArray(norm.turns) ? norm.turns : [];
for (const turn of turns) {
  const ph = Number(turn.phase);
  if (!Number.isFinite(ph) || ph <= maxQ) continue;

  const idx = history.findIndex((x) => Number(x.phase) === ph);
  const existing = idx >= 0 ? history[idx] : {};

  const incomingQ = String(turn.question_text || turn.question || '').trim();
  const incomingA = String(turn.answer_text || turn.transcript || turn.answer || '').trim();
  const hasNewScore = turn.score != null && Number.isFinite(Number(turn.score));
  const score = hasNewScore
    ? Math.max(0, Math.min(100, Math.round(Number(turn.score))))
    : (existing.score ?? null);

  const patch = {
    phase: ph,
    mode: 'live_speech',
    voice_question_number:
      Number(turn.voice_question_number || ph - maxQ) || existing.voice_question_number || null,
    question_text: incomingQ || String(existing.question_text || existing.question || '').trim(),
    answer_text: incomingA || String(existing.answer_text || '').trim(),
    received_at: turn.received_at || existing.received_at || iso,
    sent_at: turn.sent_at || existing.sent_at || iso,
    feedback: turn.feedback || existing.feedback || null,
    score,
    soft_skills: turn.soft_skills || (hasNewScore
      ? {
          clarity: Math.round(Number(turn.clarity ?? turn.score ?? 0)),
          confidence: Math.round(Number(turn.confidence ?? turn.score ?? 0)),
          professionalism: Math.round(Number(turn.professionalism ?? turn.score ?? 0)),
          relevance: Math.round(Number(turn.relevance ?? turn.score ?? 0)),
        }
      : (existing.soft_skills ?? null)),
    speech_metrics: turn.speech_metrics || existing.speech_metrics || {},
    answer_audio_url: turn.audio_url || norm.session_audio_url || existing.answer_audio_url || null,
    stt_source: turn.stt_source || 'gemini_live',
    scoring_source: turn.scoring_source || 'gemini_live',
  };

  if (idx >= 0) history[idx] = { ...existing, ...patch };
  else history.push(patch);
}

const b = String(cfg.supabase_url || sessCfg.supabase_url || '').replace(/\/+$/, '');
if (!b || !/^https?:\/\//i.test(b)) {
  throw new Error(
    'live-speech save: supabase_url missing/invalid. Set supabase_url in CFG - Live Speech Config (complete) (e.g. https://xxx.supabase.co) so voice turns persist.'
  );
}
const patchUrl = `${b}/rest/v1/${cfg.table_assessment_sessions || 'assessment_sessions'}?id=eq.${encodeURIComponent(String(session.id))}`;

// Incremental save after each voice Q&A — do not finalize the session yet.
if (norm.partial === true) {
  const lastTurn = turns[turns.length - 1] || {};
  const currentPhase = Number(lastTurn.phase || maxQ + 1);
  const partialBody = {
    interview_history: history,
    updated_at: iso,
    assessment_stage: 'live_speech',
    current_phase: currentPhase,
    status: 'assessment',
  };

  return [
    {
      json: {
        partial: true,
        ok: true,
        isFinal: false,
        session_id: session.id,
        candidate_email: norm.candidate_email || session.candidate_email,
        phase: currentPhase,
        turns_saved: turns.length,
        assessment_mode: 'live_speech',
        config: sessCfg,
        _session_patch_url: patchUrl,
        _session_patch_body: partialBody,
      },
    },
  ];
}

const techAvg =
  Number(session.technical_score) || computeTechnicalAverage(history, maxQ) || 0;
let speechAvg =
  norm.combined_speech_score != null && Number.isFinite(Number(norm.combined_speech_score))
    ? Math.round(Number(norm.combined_speech_score))
    : computeSpeechAverage(history, maxQ, speechPhases);

if (speechAvg == null) {
  const turnScores = turns
    .map((t) => Number(t.score))
    .filter((n) => Number.isFinite(n));
  speechAvg = turnScores.length
    ? Math.round(turnScores.reduce((a, b) => a + b, 0) / turnScores.length)
    : 0;
}

const combinedScore = Math.round(techAvg * techWeight + speechAvg * speechWeight);
const finalResult = combinedScore >= passThreshold ? 'PASS' : 'FAIL';
const lastPhase = maxQ + speechPhases;

const finalFeedback = [
  norm.final_feedback || norm.live_session_summary || '',
  `Technical: ${techAvg}/100 | Live communication: ${speechAvg}/100 | Combined: ${combinedScore}/100 (pass ${passThreshold}).`,
]
  .filter(Boolean)
  .join(' ');

const body = {
  interview_history: history,
  updated_at: iso,
  assessment_stage: 'completed',
  current_phase: lastPhase,
  status: 'completed',
  technical_score: techAvg,
  speech_score: speechAvg,
  score: combinedScore,
  result: finalResult,
  ...buildLiveSpeechPatchMeta(norm),
};

const lastTurn = turns[turns.length - 1] || {};
const phaseScore = Math.round(Number(lastTurn.score ?? speechAvg));

// Overall soft skills = average of every voice turn's soft skills across the
// whole interview (not per-question). This is what the candidate and emails see.
const SOFT_SKILL_KEYS = [
  'communication_clarity',
  'fluency',
  'confidence',
  'professionalism',
  'english_proficiency',
  'answer_relevance',
];
const overallSoftSkills = (() => {
  const sums = {};
  const counts = {};
  for (const t of turns) {
    const s = t && typeof t.soft_skills === 'object' ? t.soft_skills : null;
    if (!s) continue;
    for (const k of SOFT_SKILL_KEYS) {
      const v = Number(s[k]);
      if (Number.isFinite(v)) {
        sums[k] = (sums[k] || 0) + v;
        counts[k] = (counts[k] || 0) + 1;
      }
    }
  }
  const out = {};
  let any = false;
  for (const k of SOFT_SKILL_KEYS) {
    if (counts[k]) {
      out[k] = Math.round(sums[k] / counts[k]);
      any = true;
    }
  }
  return any ? out : (lastTurn.soft_skills || null);
})();

return (async () => {
  let resolvedInterviewer = sessionInterviewer || sessCfg.interviewer_email || '';
  if (!resolvedInterviewer) {
    resolvedInterviewer = await lookupJobInterviewer(
      session.requisition_id || sessionCfg.requisition_id,
      sessionCfg.requisition_title || cfg.requisition_title,
      cfg.supabase_url || sessCfg.supabase_url,
      cfg.supabase_key || sessCfg.supabase_key
    );
    if (resolvedInterviewer) {
      sessCfg.interviewer_email = resolvedInterviewer;
    }
  }

  return [
    {
      json: {
        score: combinedScore,
        phase_score: phaseScore,
        soft_skills: overallSoftSkills,
        feedback: finalFeedback,
        nextQuestion: '',
        time_limit_seconds: null,
        deadline_at: null,
        complexity_tier: null,
        isFinal: true,
        assessment_mode: 'live_speech',
        speech_phases: speechPhases,
        result: finalResult,
        average_score: combinedScore,
        candidate_email: norm.candidate_email || session.candidate_email,
        session_id: session.id,
        requisition_id: session.requisition_id || sessionCfg.requisition_id || null,
        requisition_title: sessionCfg.requisition_title || cfg.requisition_title || null,
        interviewer_email: resolvedInterviewer,
        current_phase: lastPhase,
        config: sessCfg,
        gmail_thread_id: session.gmail_thread_id || null,
        gmail_message_id: session.gmail_message_id || null,
        mail_subject: session.mail_subject || null,
        _session_patch_url: patchUrl,
        _session_patch_body: body,
      },
    },
  ];
})();

// n8n: CODE - Pick Parse Result (live speech)
function pickParseJson() {
