  `Assessment score: ${score}/100 (PASSED)\n\n` +
  `Please propose interview date/time options (45–60 minutes):\n` +
  `${schedulingLink}\n\n` +
  `Session ID: ${sessionId}\n\n` +
  `Thank you.`;

const esc = (s) =>
